import { useMemo, memo } from "react";
import { useVirtualizer } from "@tanstack/react-virtual";

const MemoizedCard = memo(function ExpensiveCard({ item }: { item: Item }) {
  return <div className="card">{/* expensive rendering */}</div>;
});

function SearchableList({ items }: { items: Item[] }) {
  const [query, setQuery] = useState("");
  const parentRef = useRef<HTMLDivElement>(null);

  // GOOD: only recalculates when items or query actually change
  const filtered = useMemo(
    () =>
      items
        .filter((item) => item.name.toLowerCase().includes(query.toLowerCase()))
        .sort((a, b) => a.name.localeCompare(b.name)),
    [items, query]
  );

  // GOOD: only renders the ~20 items visible in the viewport
  const virtualizer = useVirtualizer({
    count: filtered.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => 80,
  });

  return (
    <div>
      <input value={query} onChange={(e) => setQuery(e.target.value)} />
      <div ref={parentRef} style={{ height: 600, overflow: "auto" }}>
        <div style={{ height: virtualizer.getTotalSize() }}>
          {virtualizer.getVirtualItems().map((row) => (
            <MemoizedCard key={filtered[row.index].id} item={filtered[row.index]} />
          ))}
        </div>
      </div>
    </div>
  );
}
